            .compressor_on = false,
            .vent_open = true,
            .state = CONTROLLER_STATE_SAFE_VENT_ENUM,
            .state_name = CONTROLLER_STATE_SAFE_VENT,
            .changed = false,
            .timed_out = false,
        };
    }

    uint32_t now_ms = input.now_ms;

    // Track previous state for change detection
    bool prev_compressor_on = s_controller.compressor_on;
    bool prev_vent_open = s_controller.vent_open;

    controller_output_t output = {
        .compressor_on = s_controller.compressor_on,
        .vent_open = s_controller.vent_open,
        .state = s_controller.state,
        .state_name = CONTROLLER_STATE_SAFE_VENT,
        .changed = false,
        .timed_out = false,
    };

    // Process the input based on kind - this updates sensor freshness first
    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        // Update pressure freshness FIRST
        s_controller.has_valid_pressure = true;
        s_controller.last_pressure_kpa = input.pressure_kpa;
        s_controller.last_pressure_ms = now_ms;

        // Now check if door is also valid and closed before taking action
        if (!s_controller.has_valid_door) {
            // Door not valid yet - stay in safe vent state
            set_safe_vent_state(&s_controller);
            output.compressor_on = false;
            output.vent_open = true;
            output.state = CONTROLLER_STATE_SAFE_VENT_ENUM;
            output.state_name = CONTROLLER_STATE_SAFE_VENT;
        } else if (!s_controller.door_closed) {
            // Door is open - stay in safe vent state
            set_safe_vent_state(&s_controller);
            output.compressor_on = false;
            output.vent_open = true;
            output.state = CONTROLLER_STATE_SAFE_VENT_ENUM;
            output.state_name = CONTROLLER_STATE_SAFE_VENT;
        } else {
            // Door is valid and closed - apply pressure-based control
            if (input.pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
                // Low pressure: compress with vent closed
                s_controller.compressor_on = true;
                s_controller.vent_open = false;
                s_controller.state = CONTROLLER_STATE_PRESSURIZING_ENUM;
                output.compressor_on = true;
                output.vent_open = false;
                output.state = CONTROLLER_STATE_PRESSURIZING_ENUM;
                output.state_name = CONTROLLER_STATE_PRESSURIZING;
            } else if (input.pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
                // High pressure: vent open, compressor off
                s_controller.compressor_on = false;
                s_controller.vent_open = true;
                s_controller.state = CONTROLLER_STATE_RELIEVING_ENUM;
                output.compressor_on = false;
                output.vent_open = true;
                output.state = CONTROLLER_STATE_RELIEVING_ENUM;
                output.state_name = CONTROLLER_STATE_RELIEVING;
            } else {
                // In 40-60 band: hold previous safe output
                s_controller.state = CONTROLLER_STATE_HOLDING_ENUM;
                output.state = CONTROLLER_STATE_HOLDING_ENUM;
                output.state_name = CONTROLLER_STATE_HOLDING;
                // Keep compressor and vent in their current state
            }
        }
        break;

    case CONTROLLER_INPUT_DOOR_OPEN:
        // Update door freshness FIRST
        s_controller.has_valid_door = true;
        s_controller.door_closed = false;
        s_controller.last_door_ms = now_ms;

        // Door open forces safe vent-open state immediately
        set_safe_vent_state(&s_controller);
        output.compressor_on = false;
        output.vent_open = true;
        output.state = CONTROLLER_STATE_SAFE_VENT_ENUM;
        output.state_name = CONTROLLER_STATE_SAFE_VENT;
        break;

    case CONTROLLER_INPUT_DOOR_CLOSED:
        // Update door freshness FIRST
        s_controller.has_valid_door = true;
        s_controller.door_closed = true;
        s_controller.last_door_ms = now_ms;

        // Now check if pressure is also valid before taking action
        if (!s_controller.has_valid_pressure) {
            // Pressure not valid yet - stay in safe vent state
            set_safe_vent_state(&s_controller);
            output.compressor_on = false;
            output.vent_open = true;
            output.state = CONTROLLER_STATE_SAFE_VENT_ENUM;
            output.state_name = CONTROLLER_STATE_SAFE_VENT;
        } else {
            // Pressure is valid - apply pressure-based control
            if (s_controller.last_pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
                // Low pressure: compress with vent closed
                s_controller.compressor_on = true;
                s_controller.vent_open = false;
                s_controller.state = CONTROLLER_STATE_PRESSURIZING_ENUM;
                output.compressor_on = true;
                output.vent_open = false;
                output.state = CONTROLLER_STATE_PRESSURIZING_ENUM;
                output.state_name = CONTROLLER_STATE_PRESSURIZING;
            } else if (s_controller.last_pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
                // High pressure: vent open, compressor off
                s_controller.compressor_on = false;
                s_controller.vent_open = true;
                s_controller.state = CONTROLLER_STATE_RELIEVING_ENUM;
                output.compressor_on = false;
                output.vent_open = true;
                output.state = CONTROLLER_STATE_RELIEVING_ENUM;
                output.state_name = CONTROLLER_STATE_RELIEVING;
            } else {
                // In 40-60 band: hold previous safe output
                s_controller.state = CONTROLLER_STATE_HOLDING_ENUM;
                output.state = CONTROLLER_STATE_HOLDING_ENUM;
                output.state_name = CONTROLLER_STATE_HOLDING;
                // Keep compressor and vent in their current state
            }
        }
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_PRESSURE:
    case CONTROLLER_INPUT_INVALID_DOOR:
        // Timeout or invalid input forces safe vent-open
        set_safe_vent_state(&s_controller);
        output.compressor_on = false;
        output.vent_open = true;
        output.state = CONTROLLER_STATE_SAFE_VENT_ENUM;
        output.state_name = CONTROLLER_STATE_SAFE_VENT;
        output.timed_out = true;
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        // No input - check for timeout conditions
        bool pressure_stale = is_sensor_stale(now_ms, s_controller.has_valid_pressure, s_controller.last_pressure_ms);
        bool door_stale = is_sensor_stale(now_ms, s_controller.has_valid_door, s_controller.last_door_ms);

        if (pressure_stale || door_stale) {
            // Timeout - force safe vent state
            set_safe_vent_state(&s_controller);
            output.compressor_on = false;
            output.vent_open = true;
            output.state = CONTROLLER_STATE_SAFE_VENT_ENUM;
            output.state_name = CONTROLLER_STATE_SAFE_VENT;
            output.timed_out = true;
        } else {
            // Keep current state
            output.compressor_on = s_controller.compressor_on;
            output.vent_open = s_controller.vent_open;
            output.state = s_controller.state;

            switch (s_controller.state) {
            case CONTROLLER_STATE_SAFE_VENT_ENUM:
                output.state_name = CONTROLLER_STATE_SAFE_VENT;
                break;
            case CONTROLLER_STATE_PRESSURIZING_ENUM:
                output.state_name = CONTROLLER_STATE_PRESSURIZING;
                break;
            case CONTROLLER_STATE_HOLDING_ENUM:
                output.state_name = CONTROLLER_STATE_HOLDING;
                break;
            case CONTROLLER_STATE_RELIEVING_ENUM:
                output.state_name = CONTROLLER_STATE_RELIEVING;
                break;
            default:
                output.state_name = CONTROLLER_STATE_SAFE_VENT;
                break;
            }
        }
        break;
    }

    // Check if any actuator state changed
    if (prev_compressor_on != output.compressor_on || prev_vent_open != output.vent_open) {
        output.changed = true;
    }

    return output;
}

// Get state name for a given state
const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_SAFE_VENT_ENUM:
        return CONTROLLER_STATE_SAFE_VENT;
    case CONTROLLER_STATE_PRESSURIZING_ENUM:
        return CONTROLLER_STATE_PRESSURIZING;
    case CONTROLLER_STATE_HOLDING_ENUM:
        return CONTROLLER_STATE_HOLDING;
    case CONTROLLER_STATE_RELIEVING_ENUM:
        return CONTROLLER_STATE_RELIEVING;
    default:
        return CONTROLLER_STATE_SAFE_VENT;
    }
}

#ifndef CONTROLLER_H
#define CONTROLLER_H

#include <stdbool.h>
#include <stdint.h>

// Controller state names
#define CONTROLLER_STATE_SAFE_VENT "STATE SAFE_VENT"
#define CONTROLLER_STATE_PRESSURIZING "STATE PRESSURIZING"
#define CONTROLLER_STATE_HOLDING "STATE HOLDING"
#define CONTROLLER_STATE_RELIEVING "STATE RELIEVING"

// Controller state enum
typedef enum {
    CONTROLLER_STATE_SAFE_VENT_ENUM = 0,
    CONTROLLER_STATE_PRESSURIZING_ENUM,
    CONTROLLER_STATE_HOLDING_ENUM,
    CONTROLLER_STATE_RELIEVING_ENUM,
} controller_state_t;

// Thresholds
#define CONTROLLER_PRESSURE_LOW_THRESHOLD 40
#define CONTROLLER_PRESSURE_HIGH_THRESHOLD 60
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

// Input kinds
typedef enum {
    CONTROLLER_INPUT_NONE = 0,
    CONTROLLER_INPUT_PRESSURE,
    CONTROLLER_INPUT_DOOR_OPEN,
    CONTROLLER_INPUT_DOOR_CLOSED,
    CONTROLLER_INPUT_SENSOR_TIMEOUT,
    CONTROLLER_INPUT_INVALID_PRESSURE,
    CONTROLLER_INPUT_INVALID_DOOR,
} controller_input_kind_t;

// Input structure
typedef struct {
    controller_input_kind_t kind;
    int pressure_kpa;
    bool door_closed;
    uint32_t now_ms;
} controller_input_t;

// Controller state structure
typedef struct {
    bool compressor_on;
    bool vent_open;
    controller_state_t state;
    bool has_valid_pressure;
    int last_pressure_kpa;
    uint32_t last_pressure_ms;
    bool has_valid_door;
    bool door_closed;
    uint32_t last_door_ms;
} controller_t;

// Controller output structure
typedef struct {
    bool compressor_on;
    bool vent_open;
    controller_state_t state;
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_output_t;

// Initialize the controller
void controller_init(controller_t *controller);

// Step the controller based on input
controller_output_t controller_step(controller_t *controller, controller_input_t input);

// Get state name for a given state
const char *controller_state_name(controller_state_t state);

#endif // CONTROLLER_H
